 * 1 = Enable automatic external power switching based on battery level
 */
static scpi_result_t SCPI_SetAutoExtPower(scpi_t * context) {
    int param1;

    tPowerData * pPowerData = BoardData_Get(
            BOARDDATA_POWER_DATA,
