 50→void BQ24297_InitHardware(                                                  
 51→                        tBQ24297Config *pConfigInit,                        
 52→                        tBQ24297WriteVars *pWriteInit,                      
 53→                        tBQ24297Data *pDataInit) {
 54→    pConfigBQ24 = pConfigInit;
 55→    pWriteVariables = pWriteInit;
 56→    pData = pDataInit;
 57→
 58→    // Create I2C mutex for cross-task synchronization
 59→    if (i2cMutex == NULL) {
 60→        i2cMutex = xSemaphoreCreateMutex();
 61→        if (i2cMutex == NULL) {
 62→            LOG_E("BQ24297_InitHardware: failed to create I2C mutex");
 63→            pData->initComplete = false;
 64→            return;
 65→        }
 66→    }
 67→
 68→    // Battery management initialization (hardware interface)
 69→
 70→    // ***Disable I2C calls*** as Harmony 2.06 doesn't have a working, 
 71→    // interrupt-safe implementation
 72→    // Open the I2C Driver for Master
 73→    pData->I2C_Handle = DRV_I2C_Open(                                       
 74→                        pConfigBQ24->I2C_Index,                             
 75→                        DRV_IO_INTENT_READWRITE|DRV_IO_INTENT_BLOCKING);
 76→
 77→    // Drive OTG LOW — DPDM will set 100mA (conservative).
 78→    // ManageIINLIM state machine overrides IINLIM via I2C after DPDM completes.
 79→    BATT_MAN_OTG_OutputEnable();
 80→    BATT_MAN_OTG_Clear();
 81→}
