 83→bool BQ24297_ReadFaultReg(uint8_t *latched, uint8_t *current) {
 84→    uint8_t latchedVal = BQ24297_Read_I2C(0x09);
 85→    if (latchedVal == 0xFF) {
 86→        return false;  // First read failed — don't touch any fields
 87→    }
 88→
 89→    // Accumulate faults from the latched read
 90→    AccumulateFaults(latchedVal);
 91→    if (latched != NULL) *latched = latchedVal;
 92→
 93→    // Second read gets currently active faults
 94→    uint8_t currentVal = BQ24297_Read_I2C(0x09);
 95→    if (currentVal == 0xFF) {
 96→        // Second read failed — use latched value for status fields
 97→        LOG_E("BQ24297_ReadFaultReg: second REG09 read failed, using latched");
 98→        currentVal = latchedVal;
 99→    } else {
100→        AccumulateFaults(currentVal);
101→    }
102→
103→    if (current != NULL) *current = currentVal;
104→
105→    // Decode current value into status fields (existing behavior)
106→    pData->status.watchdog_fault = (bool)(currentVal & 0x80);
107→    pData->status.otg_fault = (bool)(currentVal & 0x40);
108→    pData->status.chgFault = (enum eChargeFault)((currentVal >> 4) & 0x03);
109→    pData->status.bat_fault = (bool)(currentVal & 0x08);
110→    pData->status.ntcFault = (enum eNTCFault)(currentVal & 0x03);
111→
112→    return true;
113→}
