 34→/**
 35→ * OR a raw REG09 value into accumulated (sticky) fault fields.
 36→ * Called for both latched and current reads so no fault is ever lost.
 37→ */
 38→static void AccumulateFaults(uint8_t reg09) {
 39→    if (reg09 & 0x80) pData->status.watchdog_faultAccum = true;
 40→    if (reg09 & 0x40) pData->status.otg_faultAccum = true;
 41→    uint8_t chgF = (reg09 >> 4) & 0x03;
 42→    if (chgF > (uint8_t)pData->status.chgFaultAccum)
 43→        pData->status.chgFaultAccum = (enum eChargeFault)chgF;
 44→    if (reg09 & 0x08) pData->status.bat_faultAccum = true;
 45→    uint8_t ntcF = reg09 & 0x03;
 46→    if (ntcF != NTC_FAULT_NORMAL)
 47→        pData->status.ntcFaultAccum = (enum eNTCFault)ntcF;
 48→}
