reg = BQ24297_Read_I2C(0x00);
// ... (lines 136-138 check HIZ bit)
BQ24297_Write_I2C(0x00, reg & 0b00000111);

// TO:
if (!BQ24297_Read_I2C(0x00, &reg)) {
    LOG_E("BQ24297_Config_Settings: REG00 read failed, skipping HIZ/VINDPM init");
} else {
