// TO:
uint8_t regs[11];
bool regOk[11];
int errCount = 0;
memset(regs, 0, sizeof(regs));
memset(regOk, 0, sizeof(regOk));
for (int i = 0; i < 11; i++) {
    if (i == 9) continue;
    if (BQ24297_Read_I2C(i, &regs[i])) {
